"""Initialize the evid package."""

from pathlib import Path
import yaml
import importlib.metadata
from evid.core.models import ConfigModel

NAME = "evid"
try:
    __version__ = importlib.metadata.version(NAME)
except importlib.metadata.PackageNotFoundError:
    __version__ = "0.0.0"


def load_config() -> dict:
    """Load and validate configuration from ~/.evidrc or return defaults."""
    config_path = Path.home() / ".evidrc"
    if config_path.exists():
        try:
            with config_path.open("r", encoding="utf-8") as f:
                user_config = yaml.safe_load(f) or {}
            config_model = ConfigModel(**user_config)
            return config_model.model_dump()
        except yaml.YAMLError:
            print("Invalid YAML in .evidrc, using defaults.")
            return ConfigModel().model_dump()
        except ValueError as e:  # Includes Pydantic ValidationError
            print(f"Validation error in .evidrc: {e}. Using defaults.")
            return ConfigModel().model_dump()
    else:
        return ConfigModel().model_dump()


CONFIG = load_config()
DEFAULT_DIR = Path(CONFIG["default_dir"]).expanduser()

"""CLI callback functions."""

import sys
from pathlib import Path
import logging
from rich.logging import RichHandler
from evid.cli.dataset import (
    list_datasets,
    select_dataset,
    create_dataset,
    track_dataset,
    get_datasets,
)

from evid.cli.evidence import label_evidence, select_evidence, get_evidence_list
from evid.core.bibtex import generate_bibtex
from evid.core.models import ConfigModel
from evid.core.rebut_doc import rebut_doc
from evid.cli.evidence import add_evidence
import yaml
from rich.console import Console
from rich.table import Table

# Set up logging with Rich handler
logging.basicConfig(handlers=[RichHandler()], level=logging.DEBUG, rich_tracebacks=True)
logger = logging.getLogger(__name__)

DIRECTORY = None


def create_callback(db: str = None, dataset: str = None):
    """Create a new dataset."""
    if not dataset:
        dataset = input("Enter new dataset name: ").strip()
        if not dataset:
            sys.exit("No dataset name provided.")
    create_dataset(DIRECTORY, dataset)


def track_callback(db: str = None, dataset: str = None):
    """Track a dataset with Git."""
    if not dataset:
        dataset = select_dataset(DIRECTORY, "Select dataset to track")
    elif dataset.isdigit():
        datasets = sorted(get_datasets(DIRECTORY))
        try:
            index = int(dataset) - 1
            if 0 <= index < len(datasets):
                dataset = datasets[index]
            else:
                sys.exit(f"Invalid dataset number: {dataset}")
        except ValueError:
            sys.exit(f"Invalid dataset number: {dataset}")
    track_dataset(DIRECTORY, dataset)


def list_datasets_callback(db: str = None):
    """List all available datasets."""
    list_datasets(DIRECTORY)


def add_callback(
    db: str = None,
    source: str = None,
    label: bool = False,
    autolabel: bool = False,
    dataset: str = None,
):
    """Add evidence from source."""
    if dataset and dataset.isdigit():
        datasets = sorted(get_datasets(DIRECTORY))
        try:
            index = int(dataset) - 1
            if 0 <= index < len(datasets):
                dataset = datasets[index]
            else:
                sys.exit(f"Invalid dataset number: {dataset}")
        except ValueError:
            sys.exit(f"Invalid dataset number: {dataset}")
    if dataset:
        if not (DIRECTORY / dataset).exists():
            sys.exit(
                f"Dataset '{dataset}' does not exist. Create it with 'evid set create'."
            )
    else:
        dataset = select_dataset(DIRECTORY, "Select dataset for adding document")
    add_evidence(DIRECTORY, dataset, source, label, autolabel)


def bibtex_callback(db: str = None, dataset: str = None, uuid: str = None):
    """Generate BibTeX for document."""
    if not dataset:
        dataset = select_dataset(
            DIRECTORY, "Select dataset for BibTeX generation", allow_create=False
        )
    if not uuid:
        uuid = select_evidence(DIRECTORY, dataset)
    typ_file = DIRECTORY / dataset / uuid / "label.typ"
    if not typ_file.exists():
        sys.exit(f"label.typ not found in {dataset}/{uuid}")
    generate_bibtex([typ_file])


def label_callback(
    db: str = None, dataset: str = None, uuid: str = None, filename: str = "label.typ"
):
    """Label a document."""
    if dataset and dataset.isdigit():
        datasets = sorted(get_datasets(DIRECTORY))
        try:
            index = int(dataset) - 1
            if 0 <= index < len(datasets):
                dataset = datasets[index]
            else:
                sys.exit(
                    f"Invalid dataset number: {dataset}. Use 'evid set list' to see available datasets."
                )
        except ValueError:
            sys.exit(f"Invalid dataset number: {dataset}")

    if not dataset:
        dataset = select_dataset(
            DIRECTORY, "Select dataset to label", allow_create=False
        )
    elif not (DIRECTORY / dataset).exists():
        sys.exit(f"Dataset '{dataset}' does not exist.")

    label_evidence(DIRECTORY, dataset, uuid, filename)


def rebut_callback(db: str = None, dataset: str = None, uuid: str = None):
    """Generate rebuttal for document."""
    if dataset and dataset.isdigit():
        datasets = sorted(get_datasets(DIRECTORY))
        try:
            index = int(dataset) - 1
            if 0 <= index < len(datasets):
                dataset = datasets[index]
            else:
                sys.exit(
                    f"Invalid dataset number: {dataset}. Use 'evid set list' to see available datasets."
                )
        except ValueError:
            sys.exit(f"Invalid dataset number: {dataset}")

    if not dataset:
        dataset = select_dataset(
            DIRECTORY, "Select dataset for rebuttal", allow_create=False
        )
    elif not (DIRECTORY / dataset).exists():
        sys.exit(f"Dataset '{dataset}' does not exist.")

    if not uuid:
        uuid = select_evidence(DIRECTORY, dataset, "Select document for rebuttal")

    workdir = DIRECTORY / dataset / uuid
    if not workdir.exists():
        sys.exit(f"Document directory {workdir} does not exist.")

    try:
        rebut_doc(workdir)
        print(f"Rebuttal generated for {dataset}/{uuid}")
    except Exception as e:
        sys.exit(f"Failed to generate rebuttal: {str(e)}")


def list_docs_callback(db: str = None, dataset: str = None, uuid: str = None):
    """List documents in dataset."""
    if dataset and dataset.isdigit():
        datasets = sorted(get_datasets(DIRECTORY))
        try:
            index = int(dataset) - 1
            if 0 <= index < len(datasets):
                dataset = datasets[index]
            else:
                sys.exit(
                    f"Invalid dataset number: {dataset}. Use 'evid set list' to see available datasets."
                )
        except ValueError:
            sys.exit(f"Invalid dataset number: {dataset}")

    if not dataset:
        dataset = select_dataset(
            DIRECTORY, "Select dataset to list", allow_create=False
        )
    elif not (DIRECTORY / dataset).exists():
        sys.exit(f"Dataset '{dataset}' does not exist.")

    if uuid:
        print(
            f"Listing specific document {uuid} in {dataset} (details not implemented)"
        )
        return

    documents = get_evidence_list(DIRECTORY, dataset)
    if not documents:
        print("No documents found.")
        return

    console = Console()
    table = Table(title=f"Documents in {dataset}")
    table.add_column("Nr", justify="right")
    table.add_column("Date")
    table.add_column("UUID")
    table.add_column("Label")

    for i, ev in enumerate(documents, 1):
        table.add_row(str(i), ev["date"], ev["uuid"], ev["title"])

    console.print(table)


def gui_callback(db: str = None):
    """Launch the GUI."""
    try:
        from evid.gui.main import main as gui_main

        gui_main(DIRECTORY)
    except ImportError:
        print("GUI requires PySide6. Install with: pip install pyside6")
        sys.exit(1)


def update_callback(db: str = None):
    """Update configuration file."""
    config_path = Path.home() / ".evidrc"
    if config_path.exists():
        try:
            with config_path.open("r") as f:
                user_config = yaml.safe_load(f) or {}
        except yaml.YAMLError:
            user_config = {}
            print("Invalid YAML in .evidrc, starting fresh.")
    else:
        user_config = {}

    # Validate and fill missing with defaults using Pydantic
    try:
        config_model = ConfigModel(**user_config)
    except ValueError:
        # If validation fails, use defaults and override with valid user values
        default_config = ConfigModel().model_dump()
        merged = {**default_config, **user_config}
        config_model = ConfigModel(**merged)  # Re-validate merged

    config = config_model.model_dump()

    # Write back the complete config
    with config_path.open("w") as f:
        yaml.dump(config, f, allow_unicode=True)

    action = "updated" if config_path.exists() else "created"
    print(f".evidrc {action} at {config_path} with complete default fields.")


def show_callback(db: str = None):
    """Show current configuration."""
    config_path = Path.home() / ".evidrc"
    defaults = ConfigModel().model_dump()
    user_config = {}
    if config_path.exists():
        try:
            with config_path.open("r") as f:
                user_config = yaml.safe_load(f) or {}
        except yaml.YAMLError:
            print("Invalid YAML in .evidrc, using defaults.")
            user_config = {}

    # Merged config (similar to load_config)
    try:
        config_model = ConfigModel(**user_config)
        merged = config_model.model_dump()
    except ValueError:
        merged = {**defaults, **user_config}
        config_model = ConfigModel(**merged)
        merged = config_model.model_dump()

    print(
        f"Config file: {config_path if config_path.exists() else 'Not found, using defaults'}"
    )
    print("Current settings:")
    for key, value in merged.items():
        if key in user_config and user_config[key] != defaults.get(key):
            source = f"overridden in {config_path}"
        else:
            source = "default"
        print(f"  {key}: {value} ({source})")

"""BibTeX utility functions for evid."""

from pathlib import Path
import re
import yaml
import pandas as pd
import demoji
import logging
import json
from evid.core.models import InfoModel

logger = logging.getLogger(__name__)


def replace_multiple_spaces(s):
    try:
        return re.sub(r" +", " ", s)
    except TypeError:
        print(s)
        return ""


def replace_underscores(s):
    try:
        return re.sub(r"_", " ", s)
    except TypeError:
        print(s)
        return ""


def remove_curly_brace_content(s):
    try:
        return re.sub(r"\{.*?\}", "", s).replace(".06em", "")
    except TypeError:
        print(s)
        return ""


def remove_backslash_substrings(s):
    try:
        return re.sub(r"\\[^ ]*", "", s)
    except TypeError:
        print(s)
        return ""


def emojis_to_text(s):
    # Replace all emojis in the content
    return demoji.replace(s, "(emoji)")


def bib_escape(s: str) -> str:
    """Escape special characters for BibTeX string fields."""
    return s.replace("\\", "\\\\").replace('"', '\\"')


def load_uuid_prefix(file_path: Path) -> str:
    info_file = file_path.with_name("info.yml")
    if info_file.exists():
        with info_file.open("r") as info_file:
            info_data = yaml.safe_load(info_file)
            # Validate with Pydantic
            try:
                validated_info = InfoModel(**info_data)
                info_data = validated_info.model_dump()
            except ValueError as e:
                logger.warning(f"Validation error for {info_file}: {e}")
                return ""
            if "uuid" in info_data:
                return info_data["uuid"][:4]
    return ""


def load_url(file_path: Path) -> str:
    info_file = file_path.with_name("info.yml")
    if info_file.exists():
        with info_file.open("r") as info_file:
            info_data = yaml.safe_load(info_file)
            # Validate with Pydantic
            try:
                validated_info = InfoModel(**info_data)
                info_data = validated_info.model_dump()
            except ValueError as e:
                logger.warning(f"Validation error for {info_file}: {e}")
                return ""
            if "url" in info_data:
                return str(info_data["url"])
    return ""


def load_authors(file_path: Path) -> str:
    """Load authors from info.yml."""
    info_file = file_path.with_name("info.yml")
    if info_file.exists():
        with info_file.open("r") as info_file:
            info_data = yaml.safe_load(info_file)
            # Validate with Pydantic
            try:
                validated_info = InfoModel(**info_data)
                info_data = validated_info.model_dump()
            except ValueError as e:
                logger.warning(f"Validation error for {info_file}: {e}")
                return ""
            if "authors" in info_data:
                return str(info_data["authors"])
    return ""


def load_title(file_path: Path) -> str:
    info_file = file_path.with_name("info.yml")
    if info_file.exists():
        with info_file.open("r") as info_file:
            info_data = yaml.safe_load(info_file)
            # Validate with Pydantic
            try:
                validated_info = InfoModel(**info_data)
                info_data = validated_info.model_dump()
            except ValueError as e:
                logger.warning(f"Validation error for {info_file}: {e}")
                return ""
            if "title" in info_data:
                return str(info_data["title"])
    return ""


def load_dates(file_path: Path) -> str:
    info_file = file_path.with_name("info.yml")
    if info_file.exists():
        with info_file.open("r") as info_file:
            info_data = yaml.safe_load(info_file)
            # Validate with Pydantic
            try:
                validated_info = InfoModel(**info_data)
                info_data = validated_info.model_dump()
            except ValueError as e:
                logger.warning(f"Validation error for {info_file}: {e}")
                return ""
            if "dates" in info_data:
                return str(info_data["dates"])
    return ""


def json_to_bib(json_file: Path, output_file: Path, exclude_note: bool):
    try:
        with open(json_file) as f:
            data = json.load(f)
        if not data:
            raise ValueError("JSON data is empty")
        df = pd.DataFrame([item["value"] for item in data])
        if df.empty:
            raise ValueError("DataFrame is empty")
        if "key" not in df.columns:
            raise KeyError("'key' column missing in JSON data")
        df.rename(columns={"key": "label", "text": "quote"}, inplace=True)
        df["date"] = pd.to_datetime(
            df.get("date", pd.Series([pd.NaT] * len(df))),
            dayfirst=False,
            errors="coerce",
        )
        uuid_prefix = load_uuid_prefix(json_file)
        df["latex_label"] = [f"{uuid_prefix}:{label.strip()}" for label in df["label"]]
        with open(output_file, "w", encoding="utf-8") as bibtex_file:
            # Write main document entry first
            main_lines = [f"@article{{ {uuid_prefix}:main  ,"]
            title_value = replace_underscores(
                replace_multiple_spaces(
                    remove_curly_brace_content(
                        remove_backslash_substrings(load_title(json_file))
                    )
                )
            )
            if title_value:
                main_lines.append(f"    title = {{{title_value}}},")
            author_value = load_authors(json_file)
            if author_value:
                main_lines.append(f"    author = {{{author_value}}},")
            date_value = load_dates(json_file)
            if date_value:
                main_lines.append(f"    date = {{{date_value}}},")
            url_value = load_url(json_file)
            if url_value:
                main_lines.append(f"    url = {{{url_value}}},")
            main_lines.append("    }")
            bibtex_file.write(emojis_to_text("\n".join(main_lines)) + "\n")

            # Write snippet entries
            for index, row in df.iterrows():
                entry_lines = [f"@article{{ {row['latex_label']}  ,"]

                note_value = row.get("note", "")
                if note_value:
                    note_key = "nonote" if exclude_note else "note"
                    entry_lines.append(f"    {note_key} = {{{note_value}}},")

                title_value = replace_underscores(
                    replace_multiple_spaces(
                        remove_backslash_substrings(row.get("quote", ""))
                    )
                )
                if title_value:
                    entry_lines.append(f"    title = {{{title_value}}},")

                journal_value = replace_underscores(
                    replace_multiple_spaces(
                        remove_curly_brace_content(
                            remove_backslash_substrings(row.get("title", ""))
                        )
                    )
                )
                if journal_value and journal_value != "NAME":
                    entry_lines.append(f"    journal = {{{journal_value}}},")

                author_value = load_authors(json_file)
                if author_value:
                    entry_lines.append(f"    author = {{{author_value}}},")

                date_value = (
                    row["date"].strftime("%Y-%m-%d")
                    if not pd.isnull(row["date"])
                    else ""
                )
                if date_value:
                    entry_lines.append(f"    date = {{{date_value}}},")

                pages_value = (
                    int(row.get("opage", ""))
                    if "opage" in row and not pd.isnull(row.get("opage", ""))
                    else ""
                )
                if pages_value:
                    entry_lines.append(f"    pages = {{{pages_value}}},")

                url_value = load_url(json_file)
                if url_value:
                    entry_lines.append(f"    url = {{{url_value}}},")

                entry_lines.append("    }")
                bibtex_entry = "\n".join(entry_lines)
                bibtex_file.write(emojis_to_text(bibtex_entry) + "\n")
    except Exception as e:
        raise ValueError(f"Error processing JSON: {e}")

"""Database handling for evid."""

import yaml
from pathlib import Path
from typing import Dict, List
from evid import DEFAULT_DIR
from evid.core.models import InfoModel  # Added for validation


class Database:
    def __init__(self, db_path: Path = DEFAULT_DIR, datasets: List[str] = None):
        self.db: Dict[str, Dict] = {}
        if datasets is None:
            datasets = [
                d.name
                for d in db_path.iterdir()
                if d.is_dir() and not d.name.startswith(".")
            ]
        for dataset in datasets:
            self.db[dataset] = {}
            for info_file in db_path.glob(f"{dataset}/**/info.yml"):
                try:
                    with info_file.open() as f:
                        entry = yaml.safe_load(f)
                        # Validate with Pydantic
                        validated_entry = InfoModel(**entry)
                        entry = validated_entry.model_dump()
                        key = f"{entry.get('title', '')} {entry['uuid']}"
                        self.db[dataset][key] = entry
                except ValueError as e:
                    print(f"Validation error for {info_file}: {e}. Skipping.")
                    continue
                except Exception:
                    continue

    def get_filenames(self) -> List[str]:
        return [
            entry["original_name"]
            for dataset in self.db.values()
            for entry in dataset.values()
            if "original_name" in entry
        ]

"""Main GUI application."""

import sys
import os
from PySide6.QtWidgets import QApplication, QMainWindow, QTabWidget
from PySide6.QtGui import QPalette, QColor, QKeySequence
from PySide6.QtCore import Qt
from PySide6.QtGui import QShortcut
from pathlib import Path
from .tabs.add_evidence import AddEvidenceTab
from .tabs.browse_evidence import BrowseEvidenceTab
from evid import DEFAULT_DIR


class EvidenceManagerApp(QMainWindow):
    """Main application window for evid GUI."""

    def __init__(self, directory: Path):
        super().__init__()
        self.directory = directory
        self.setWindowTitle("evid")
        self.resize(800, 600)

        # Detect system theme and apply accordingly
        self.apply_theme()

        # Setup tabs
        self.tabs = QTabWidget()
        self.setCentralWidget(self.tabs)

        self.add_tab = AddEvidenceTab(self.directory)
        self.browse_tab = BrowseEvidenceTab(self.directory)

        self.tabs.addTab(self.add_tab, "Add")
        self.tabs.addTab(self.browse_tab, "Browse")
        self.tabs.setCurrentIndex(1)  # Set Browse tab as active initially

        # Setup keyboard shortcuts
        self.setup_shortcuts()

    def is_dark_mode(self):
        """Detect if system prefers dark mode."""
        try:
            from PySide6.QtGui import QGuiApplication

            if hasattr(QGuiApplication.styleHints(), "colorScheme"):
                return QGuiApplication.styleHints().colorScheme() == Qt.ColorScheme.Dark
        except AttributeError:
            pass
        # Fallback: assume light mode
        return False

    def apply_theme(self):
        """Apply light or dark theme based on system preference."""
        if self.is_dark_mode():
            self.set_dark_theme()
        else:
            self.set_light_theme()

    def set_dark_theme(self):
        """Apply a consistent dark theme."""
        palette = QPalette()
        # Background colors
        palette.setColor(QPalette.ColorRole.Window, QColor("#2e2e2e"))
        palette.setColor(QPalette.ColorRole.Base, QColor("#3e3e3e"))
        palette.setColor(QPalette.ColorRole.AlternateBase, QColor("#353535"))
        # Text colors
        palette.setColor(QPalette.ColorRole.WindowText, QColor("#ffffff"))
        palette.setColor(QPalette.ColorRole.Text, QColor("#ffffff"))
        palette.setColor(QPalette.ColorRole.ToolTipText, QColor("#ffffff"))
        # Button and highlight colors
        palette.setColor(QPalette.ColorRole.Button, QColor("#4a4a4a"))
        palette.setColor(QPalette.ColorRole.ButtonText, QColor("#ffffff"))
        palette.setColor(QPalette.ColorRole.Highlight, QColor("#0078d4"))
        palette.setColor(QPalette.ColorRole.HighlightedText, QColor("#ffffff"))
        # Disabled elements
        palette.setColor(QPalette.ColorRole.PlaceholderText, QColor("#888888"))
        palette.setColor(QPalette.ColorRole.Light, QColor("#555555"))
        palette.setColor(QPalette.ColorRole.Mid, QColor("#444444"))
        palette.setColor(QPalette.ColorRole.Dark, QColor("#333333"))
        # Tooltip background
        palette.setColor(QPalette.ColorRole.ToolTipBase, QColor("#2e2e2e"))

        self.setPalette(palette)
        # Ensure stylesheet enforces dark theme for elements not covered by palette
        self.setStyleSheet(""""
            QToolTip { background-color: #2e2e2e; color: #ffffff; border: 1px solid #555555; }
            QComboBox, QLineEdit, QTextEdit, QTableWidget { 
                background-color: #3e3e3e; 
                color: #ffffff; 
                border: 1px solid #555555; 
            }
            QPushButton { 
                background-color: #4a4a4a; 
                color: #ffffff; 
                border: 1px solid #555555; 
            }
            QPushButton:hover { 
                background-color: #0078d4; 
            }
            QTabBar::tab { 
                background: #3e3e3e; 
                color: #ffffff; 
                padding: 5px; 
            }
            QTabBar::tab:selected { 
                background: #0078d4; 
            }
        """)

    def set_light_theme(self):
        """Apply a consistent light theme."""
        palette = QPalette()
        # Use default light colors
        palette.setColor(QPalette.ColorRole.Window, QColor("#f0f0f0"))
        palette.setColor(QPalette.ColorRole.Base, QColor("#ffffff"))
        palette.setColor(QPalette.ColorRole.AlternateBase, QColor("#f7f7f7"))
        palette.setColor(QPalette.ColorRole.WindowText, QColor("#000000"))
        palette.setColor(QPalette.ColorRole.Text, QColor("#000000"))
        palette.setColor(QPalette.ColorRole.ToolTipText, QColor("#000000"))
        palette.setColor(QPalette.ColorRole.Button, QColor("#e0e0e0"))
        palette.setColor(QPalette.ColorRole.ButtonText, QColor("#000000"))
        palette.setColor(QPalette.ColorRole.Highlight, QColor("#0078d4"))
        palette.setColor(QPalette.ColorRole.HighlightedText, QColor("#ffffff"))
        palette.setColor(QPalette.ColorRole.PlaceholderText, QColor("#777777"))
        palette.setColor(QPalette.ColorRole.Light, QColor("#ffffff"))
        palette.setColor(QPalette.ColorRole.Mid, QColor("#c0c0c0"))
        palette.setColor(QPalette.ColorRole.Dark, QColor("#a0a0a0"))
        palette.setColor(QPalette.ColorRole.ToolTipBase, QColor("#f0f0f0"))

        self.setPalette(palette)
        self.setStyleSheet(""""
            QToolTip { background-color: #f0f0f0; color: #000000; border: 1px solid #a0a0a0; }
            QComboBox, QLineEdit, QTextEdit, QTableWidget { 
                background-color: #ffffff; 
                color: #000000; 
                border: 1px solid #a0a0a0; 
            }
            QPushButton { 
                background-color: #e0e0e0; 
                color: #000000; 
                border: 1px solid #a0a0a0; 
            }
            QPushButton:hover { 
                background-color: #0078d4; 
            }
            QTabBar::tab { 
                background: #f0f0f0; 
                color: #000000; 
                padding: 5px; 
            }
            QTabBar::tab:selected { 
                background: #0078d4; 
            }
        """)

    def setup_shortcuts(self):
        """Setup keyboard shortcuts for tab navigation, app closing, labeling, and BibTeX generation."""
        # Ctrl+PageUp to switch to Add tab
        add_tab_shortcut = QShortcut(
            QKeySequence("Ctrl+PageUp"),
            self,
            lambda: self.tabs.setCurrentIndex(0),
        )
        add_tab_shortcut.setContext(Qt.ShortcutContext.ApplicationShortcut)

        # Ctrl+PageDown to switch to Browse tab
        browse_tab_shortcut = QShortcut(
            QKeySequence("Ctrl+PageDown"),
            self,
            lambda: self.tabs.setCurrentIndex(1),
        )
        browse_tab_shortcut.setContext(Qt.ShortcutContext.ApplicationShortcut)

        # Ctrl+W to close the application
        QShortcut(QKeySequence("Ctrl+W"), self, self.close)

        # Ctrl+L to trigger labeling in Browse tab
        QShortcut(
            QKeySequence("Ctrl+L"),
            self,
            lambda: self.browse_tab.create_labels()
            if self.tabs.currentWidget() == self.browse_tab
            else None,
        )

        # Ctrl+B to trigger BibTeX generation in Browse tab
        QShortcut(
            QKeySequence("Ctrl+B"),
            self,
            lambda: self.browse_tab.generate_bibtex()
            if self.tabs.currentWidget() == self.browse_tab
            else None,
        )


def main(directory=DEFAULT_DIR):
    """Launch the GUI application."""
    # Check for headless mode
    headless = (
        os.environ.get("QT_QPA_PLATFORM") == "offscreen"
        or os.environ.get("HEADLESS") == "1"
    )
    app = QApplication(sys.argv)
    window = EvidenceManagerApp(Path(directory))
    window.show()
    if headless:
        # In headless mode, don't start the event loop
        return
    sys.exit(app.exec())

"""Text normalization utilities."""


def normalize_text(text: str | bytes | None, default: str = "") -> str:
    """Normalize text to UTF-8, preserving Danish characters (æ, ø, å)."""
    if text is None:
        return default
    if isinstance(text, bytes):
        try:
            text = text.decode("utf-8")
        except UnicodeDecodeError:
            text = text.decode("latin-1", errors="replace")
    text = str(text).strip()
    return text
